import{_ as a,o,c as e,a0 as r}from"./chunks/framework.CED9SG98.js";const c=JSON.parse('{"title":"吹了几年的 AI 个人知识库，为什么还是那么难用？Karpathy 的 Wiki 并不是解决方案","description":"Datawhale 公众号深度技术文章，将 AI 记忆系统重新定义为「知识运行时」问题，提出四类方案对比、三层架构主张与可验证性指标","frontmatter":{"type":"Source","title":"吹了几年的 AI 个人知识库，为什么还是那么难用？Karpathy 的 Wiki 并不是解决方案","description":"Datawhale 公众号深度技术文章，将 AI 记忆系统重新定义为「知识运行时」问题，提出四类方案对比、三层架构主张与可验证性指标","source_url":"https://mp.weixin.qq.com/s/DJtp4QUJtJHCnNU9yarsww","source_title":"吹了几年的 AI 个人知识库，为什么还是那么难用？Karpathy 的 Wiki 并不是解决方案","source_author":"(Datawhale 公众号)","source_platform":"微信公众号 (mp.weixin.qq.com)","ingest_date":"2026-07-13T00:00:00.000Z","access_date":"2026-07-13T00:00:00.000Z","captured_by":"weixin-article-reader v1.1.0","image_count":4,"word_count":"~8000","tags":["知识管理","PKMS","AI记忆","运行时","Hermes","OpenClaw","Karpathy","LLM-Wiki","主张"],"status":"compiled","review_count":0,"last_review":"2026-07-13T00:00:00.000Z","next_review":"2026-08-12T00:00:00.000Z"},"headers":[],"relativePath":"wiki/sources/2026-07-13-datawhale-karpathy-knowledge-base-runtime.md","filePath":"wiki/sources/2026-07-13-datawhale-karpathy-knowledge-base-runtime.md"}'),i={name:"wiki/sources/2026-07-13-datawhale-karpathy-knowledge-base-runtime.md"};function l(n,t,s,u,h,d){return o(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="吹了几年的-ai-个人知识库-为什么还是那么难用-karpathy-的-wiki-并不是解决方案" tabindex="-1">吹了几年的 AI 个人知识库，为什么还是那么难用？Karpathy 的 Wiki 并不是解决方案 <a class="header-anchor" href="#吹了几年的-ai-个人知识库-为什么还是那么难用-karpathy-的-wiki-并不是解决方案" aria-label="Permalink to &quot;吹了几年的 AI 个人知识库，为什么还是那么难用？Karpathy 的 Wiki 并不是解决方案&quot;">​</a></h1><blockquote><p>原文: Datawhale 公众号 (2026-04-27) 链接: <a href="https://mp.weixin.qq.com/s/DJtp4QUJtJHCnNU9yarsww" target="_blank" rel="noreferrer">https://mp.weixin.qq.com/s/DJtp4QUJtJHCnNU9yarsww</a> 完整原文 + 图片: [[raw/articles/2026-07-13-datawhale-karpathy-knowledge-base-runtime]]</p></blockquote><h2 id="核心论点" tabindex="-1">核心论点 <a class="header-anchor" href="#核心论点" aria-label="Permalink to &quot;核心论点&quot;">​</a></h2><p><strong>AI 个人知识库的真正问题不是「把资料存好，让 AI 搜」，而是如何让一份长期知识状态在 AI 系统里稳定运行。</strong> 这是「运行时」问题，不是「存储与检索」问题。</p><blockquote><p>&quot;模型可以提议，但谁来负责事实？&quot; — 这是全文最尖锐的发问。</p></blockquote><h2 id="四类方案对比-与本文核心分类" tabindex="-1">四类方案对比（与本文核心分类） <a class="header-anchor" href="#四类方案对比-与本文核心分类" aria-label="Permalink to &quot;四类方案对比（与本文核心分类）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类别</th><th>代表</th><th>能做什么</th><th>根本缺陷</th></tr></thead><tbody><tr><td>文档知识库</td><td>Obsidian + RAG</td><td>检索、问答</td><td>本质是检索系统，<strong>不是知识维护系统</strong>；判断不会自动继承</td></tr><tr><td>模型自己沉淀</td><td>OpenClaw 早期</td><td>自我总结、自我归档</td><td>模型<strong>既负责提议又负责决定真相</strong>，危险</td></tr><tr><td>记忆运行时</td><td>Hermes</td><td>冻结快照、异步管线、prefetch</td><td>工程复杂，但解决了漂移</td></tr><tr><td>LLM Wiki</td><td>Karpathy 方案</td><td>资料进来即综合</td><td>综合开始积累，但<strong>证据容易变软</strong></td></tr></tbody></table><h2 id="关键概念" tabindex="-1">关键概念 <a class="header-anchor" href="#关键概念" aria-label="Permalink to &quot;关键概念&quot;">​</a></h2><h3 id="四层「记忆」要分开" tabindex="-1">四层「记忆」要分开 <a class="header-anchor" href="#四层「记忆」要分开" aria-label="Permalink to &quot;四层「记忆」要分开&quot;">​</a></h3><p>作者把混乱的&quot;记忆&quot;讨论拆成四层：</p><ol><li><strong>文档知识库</strong>（Obsidian/Notion/RAG）：资料放在哪里、怎么搜出来</li><li><strong>会话上下文管理</strong>（摘要/压缩）：一场对话太长怎么塞窗口</li><li><strong>智能体的记忆运行时</strong>：长期 agent 何时读/写/审/冻结</li><li><strong>个人知识状态系统</strong>：一个人/项目/领域的长期知识如何在几年里保持准确、可审计、可更新</li></ol><blockquote><p><strong>绝大多数讨论在第一层打转</strong>，作者认为真正的挑战在第三、四层。</p></blockquote><h3 id="底层四个约束" tabindex="-1">底层四个约束 <a class="header-anchor" href="#底层四个约束" aria-label="Permalink to &quot;底层四个约束&quot;">​</a></h3><p>为什么这件事五年还没做对？因为四类方案都只正面回答了一两条约束，<strong>没有任何一派同时回答了所有约束</strong>：</p><ul><li>系统看不到真实世界，只能看到观察记录</li><li>上下文窗口永远有限</li><li>历史意义会变化</li><li>模型本身不是可靠存储器</li></ul><blockquote><p>一句话总结：<strong>如何在有限上下文、变化的世界、不可靠的抽取器之间，维护一份可验证的知识状态？</strong></p></blockquote><h3 id="危险案例" tabindex="-1">危险案例 <a class="header-anchor" href="#危险案例" aria-label="Permalink to &quot;危险案例&quot;">​</a></h3><blockquote><p>用户让 agent 整理邮箱，明确说&quot;在自己确认之前不要执行任何动作&quot;。后来对话变长，系统触发上下文压缩，把历史摘要化。结果**&quot;不要执行任何动作&quot;这条关键约束在摘要里丢了**。</p></blockquote><p>教训：<strong>约束不能只是对话里的一句话</strong>，它应该被当成不可随便压缩、不可随便覆盖的结构化对象。</p><h3 id="主张-vs-段落" tabindex="-1">主张 vs 段落 <a class="header-anchor" href="#主张-vs-段落" aria-label="Permalink to &quot;主张 vs 段落&quot;">​</a></h3><p>作者提出一个重要判断：<strong>长期知识的基本单位不应该是段落，而应该是&quot;主张&quot;（claim）</strong>。</p><ul><li>一条主张应该有：主体、谓词、对象、限定条件、证据、置信度、状态</li><li>段落很难被精确反驳，主张可以</li><li>文件级 / 段落级粒度无法回答&quot;这条判断什么时候过期、和旧判断冲突怎么办&quot;</li></ul><h2 id="作者的三层架构" tabindex="-1">作者的三层架构 <a class="header-anchor" href="#作者的三层架构" aria-label="Permalink to &quot;作者的三层架构&quot;">​</a></h2><h3 id="运行时层-保证系统不漂移" tabindex="-1">运行时层（保证系统不漂移） <a class="header-anchor" href="#运行时层-保证系统不漂移" aria-label="Permalink to &quot;运行时层（保证系统不漂移）&quot;">​</a></h3><ul><li><strong>统一的运行时边界</strong>：所有记忆操作过一个总调度台，不能&quot;这里也能写那里也能写&quot;</li><li><strong>冻结视图</strong>：会话开始时把当前记忆状态冻结成一份只读视图，会话中途不修改 prompt 已看到的部分</li><li><strong>异步管线</strong>：不是主 agent 在 turn 里现查现写，而是后台线程做 sync + prefetch</li><li><strong>审计可追</strong>：记忆什么时候进来、什么时候出去、谁来管、坏了能不能追</li></ul><h3 id="知识层-保证事实有证据" tabindex="-1">知识层（保证事实有证据） <a class="header-anchor" href="#知识层-保证事实有证据" aria-label="Permalink to &quot;知识层（保证事实有证据）&quot;">​</a></h3><ul><li>基本单位是<strong>主张</strong>，不是段落</li><li>主张绑定证据、时间、置信度、状态</li><li>低风险自动接受，中高风险进入审核</li><li>通过审核的主张进入长期状态，所有视图（对话、维基、报告、上下文包）从同一份状态投影</li></ul><h3 id="权限层-保证系统不会乱动手" tabindex="-1">权限层（保证系统不会乱动手） <a class="header-anchor" href="#权限层-保证系统不会乱动手" aria-label="Permalink to &quot;权限层（保证系统不会乱动手）&quot;">​</a></h3><p>四权分离：</p><ol><li><strong>事实写入权</strong>：模型只能提议，不能直接写成长期事实</li><li><strong>约束写入权</strong>：&quot;不要自动删邮件&quot;&quot;没确认前不要执行&quot;必须结构化存储，不能被压缩</li><li><strong>工具执行权</strong>：删邮件/发消息/转账/改生产代码不因模型&quot;觉得应该做&quot;而执行</li><li><strong>回顾撤销权</strong>：人可以推翻任何系统决策</li></ol><blockquote><p><strong>危险动作不走记忆链路，单独走权限审批</strong>。</p></blockquote><h2 id="评估指标" tabindex="-1">评估指标 <a class="header-anchor" href="#评估指标" aria-label="Permalink to &quot;评估指标&quot;">​</a></h2><p>作者提出五个可观测指标判断这套东西有没有真的变好：</p><ol><li>长期主张有多少能追到原始资料的具体段落？</li><li>新资料和旧主张冲突时，系统能不能发现？</li><li>过期主张能不能被降权或失效？</li><li>同一场对话里的记忆是否稳定（会不会说着说着变掉）？</li><li>审核负担有多重？每一百条候选主张要人工审几条？</li></ol><h2 id="与-pkms-现有知识的关系" tabindex="-1">与 PKMS 现有知识的关系 <a class="header-anchor" href="#与-pkms-现有知识的关系" aria-label="Permalink to &quot;与 PKMS 现有知识的关系&quot;">​</a></h2><ul><li>[[concepts/PKMS]] — PKMS 本身就是这个探索的产物，本文的&quot;运行时层&quot;对应 PKMS 的多轨制</li><li>[[sources/2026-07-12-karpathy-zhishiku-huiche]] — Andrew 小红书版（用户认知角度，与本文互补：本文讲&quot;系统怎么运行&quot;，Andrew 讲&quot;用户该做什么&quot;）</li><li>[[entities/Karpathy]] — 同一议题不同视角，Karpathy 提供方案（LLM Wiki），本文指出其证据软肋</li><li>[[concepts/AI-Assisted-Thinking]] — 本文给出 AI 不可越权写入事实的边界</li><li>[[entities/Hermes]] — 唯一真正实现&quot;运行时层&quot;的现有系统</li><li>[[entities/OpenClaw]] — 第二类方案的代表（自我沉淀），有&quot;既提议又决定&quot;的风险</li></ul><h2 id="关键引用" tabindex="-1">关键引用 <a class="header-anchor" href="#关键引用" aria-label="Permalink to &quot;关键引用&quot;">​</a></h2><blockquote><p>&quot;真正难的不是『把资料存好，让AI搜』，真正难的是：让一份长期知识状态，在AI系统里稳定运行。&quot;</p></blockquote><blockquote><p>&quot;模型可以提议，但谁来负责事实？&quot;</p></blockquote><blockquote><p>&quot;段落很难被精确反驳。主张可以。&quot;</p></blockquote><blockquote><p>&quot;危险动作不走记忆链路，单独走权限审批。&quot;</p></blockquote><blockquote><p>&quot;不是因为模型不够强、数据库选错，是没有任何一派同时回答了所有约束。&quot;</p></blockquote><h2 id="我的判断" tabindex="-1">我的判断 <a class="header-anchor" href="#我的判断" aria-label="Permalink to &quot;我的判断&quot;">​</a></h2><p>这篇是 2026 年 AI 个人知识库讨论里<strong>最系统化的一篇技术反思</strong>。它的贡献不在于给出答案（作者自己说还在摸索），而在于：</p><ol><li><strong>给出分类学</strong>：四类方案横向对比，让讨论不再鸡同鸭讲</li><li><strong>把问题正名为「运行时」</strong>：让&quot;知识库&quot;这个被玩烂的词重新有了工程边界</li><li><strong>三层架构 + 四权分离</strong>：给出了可对照的设计清单</li><li><strong>可观测指标</strong>：把&quot;AI 记忆有没有变好&quot;从主观判断变成了可量化的问题</li></ol><p>最值得采纳的两个具体动作：</p><ul><li><strong>把&quot;约束&quot;从对话摘要里拆出来，单独结构化存储</strong>（避免本次危险案例再次发生）</li><li><strong>把&quot;主张&quot;作为知识库的基本单位</strong>（段落级粒度无法精确反驳）</li></ul><hr><p><em>原文: 微信公众号 Datawhale，2026-04-27</em><em>完整原文含 4 张图: [[raw/articles/2026-07-13-datawhale-karpathy-knowledge-base-runtime]]</em></p>',49)])])}const p=a(i,[["render",l]]);export{c as __pageData,p as default};
